rule.violation_response:
НЕМЕДЛЕННО остановиться и сообщить:
"❌ НАРУШЕНИЕ: Попытка изменить файл вне текущего пакета.
Текущий пакет: {current_package}
Попытка изменить: {attempted_path}
Это запрещено правилами архитектуры."

step.output:
"✅ Готов к работе с пакетом {package_name}
Scope: {CURRENT_PACKAGE}/
Зависимости от aq_schema: {список интерфейсов}"

pattern.example:
// aq_schema/clients.dart
abstract interface class IAQVaultClient {
  Future<void> write(String key, dynamic value);
}

// current_package/lib/client/vault_client.dart
class VaultClient implements IAQVaultClient {
  @override
  Future<void> write(String key, dynamic value) {
    // реализация
  }
}

// current_package/lib/my_package.dart
export 'client/vault_client.dart';

user_messages.on_scope_violation:
"❌ НАРУШЕНИЕ SCOPE
Текущий пакет: {CURRENT_PACKAGE}
Попытка изменить: {attempted_path}

Это нарушает архитектурные правила.
Изменения разрешены только внутри текущего пакета."

user_messages.on_other_package_write_attempt:
"❌ ЗАПРЕЩЕНО: Изменение другого пакета

Текущий пакет: {CURRENT_PACKAGE}
Попытка изменить: {other_package}

Пакеты изолированы. Для изменения другого пакета
нужно начать новую сессию с ним как текущим."
